        .clk(clk),
        .write_enable(write_enable),
        .write_addr(write_addr),
        .addr(addr_out),
        .write_data(write_data),
        .data_out(read_data)
    );

    // -----------------------------------
    // Multiplier-Accumulator Block
    // -----------------------------------
    matvec #(
        .IWIDTH(pixel_data_width),
        .SIGWIDTH(SIGWIDTH),
        .EWIDTH(EWIDTH),
        .M(K),
        .N(number_of_columns_per_frame)
    ) mac (
        .clk(clk),
        .do_acc(do_acc),
        .dv(dv),
        .in(pixel_data),
        .weights(read_data),
        .out(result)
    );

endmodule

